pub(super) fn nearest_value(freqs: &Array1<f64>, values: &Array1<f64>, target: f64) -> f64 {
    let idx = freqs
        .iter()
        .enumerate()
        .min_by(|(_, a), (_, b)| {
            (*a - target)
                .abs()
                .partial_cmp(&(*b - target).abs())
                .unwrap()
        })
        .map(|(idx, _)| idx)
        .unwrap();
    values[idx]
}

